{"version":3,"file":"messageTest.js","sourceRoot":"","sources":["../../test/messageTest.ts"],"names":[],"mappings":";;;;;;;;;;;;;;AAAA,+DAAiE;AAEjE,oDAA2B;AAC3B,0DAA0B;AAC1B,mDAAsE;AACtE,4CAAmB;AACnB,mCAA0C;AAC1C,+BAAgC;AAEhC,gCAA8C;AAE9C,MAAM,aAAa,GAAG,IAAA,gBAAS,EAAC,iBAAQ,CAAC,CAAA;AAEzC,QAAQ,CAAC,uBAAuB,EAAE,GAAG,EAAE;IACrC,MAAM,UAAU,GAAG,IAAA,kCAA2B,EAAC,SAAS,CAAC,CAAA;IACzD,MAAM,iBAAiB,GAAG,mBAAE,CAAC,IAAI,CAAC,GAAG,UAAU,uBAAuB,CAAC,CAAA;IACvE,MAAM,eAAe,GAAG,mBAAE,CAAC,IAAI,CAC7B,GAAG,UAAU,mEAAmE,CACjF,CAAA;IACD,MAAM,YAAY,GAAG,EAAE,CAAC,MAAM,CAAC,iBAAiB,EAAE,eAAe,CAAC,CAAA;IAElE,EAAE,CAAC,wCAAwC,EAAE,GAAG,EAAE;QAChD,gBAAM,CAAC,QAAQ,CAAC,YAAY,CAAC,MAAM,EAAE,CAAC,CAAC,CAAA;IACzC,CAAC,CAAC,CAAA;IAEF,KAAK,MAAM,WAAW,IAAI,YAAY,EAAE,CAAC;QACvC,EAAE,CAAC,wCAAwC,WAAW,EAAE,EAAE,GAAS,EAAE;YACnE,MAAM,aAAa,GAAG,IAAI,uCAAqB,EAAE,CAAA;YAEjD,MAAM,aAAa,CACjB,YAAE,CAAC,gBAAgB,CAAC,WAAW,EAAE,OAAO,CAAC,EACzC,aAAa,EACb,IAAI,iBAAQ,CAAC;gBACX,UAAU,EAAE,IAAI;gBAChB,KAAK,CACH,QAA2B,EAC3B,SAAiB,EACjB,QAAwC;oBAExC,IAAI,CAAC;wBACH,IAAI,QAAQ,CAAC,eAAe,EAAE,CAAC;4BAC7B,MAAM,MAAM,GAAG,IAAI,2BAAqB,EAAE,CAAA;4BAC1C,MAAM,CAAC,mBAAmB,CAAC,QAAQ,CAAC,eAAe,CAAC,CAAA;wBACtD,CAAC;wBACD,QAAQ,EAAE,CAAA;oBACZ,CAAC;oBAAC,OAAO,KAAK,EAAE,CAAC;wBACf,KAAK,CAAC,OAAO,IAAI,KAAK,QAAQ,CAAC,eAAe,CAAC,GAAG,IAAI,CAAA;wBACtD,QAAQ,CAAC,KAAK,CAAC,CAAA;oBACjB,CAAC;gBACH,CAAC;aACF,CAAC,CACH,CAAA;QACH,CAAC,CAAA,CAAC,CAAC,OAAO,CAAC,KAAK,CAAC,CAAA;IACnB,CAAC;AACH,CAAC,CAAC,CAAA","sourcesContent":["import { NdjsonToMessageStream } from '@cucumber/message-streams'\nimport * as messages from '@cucumber/messages'\nimport assert from 'assert'\nimport fg from 'fast-glob'\nimport { convertWindowsPathToPattern } from 'fast-glob/out/utils/path'\nimport fs from 'fs'\nimport { pipeline,Writable } from 'stream'\nimport { promisify } from 'util'\n\nimport { GherkinDocumentWalker } from '../src'\n\nconst asyncPipeline = promisify(pipeline)\n\ndescribe('Walking with messages', () => {\n  const currentDir = convertWindowsPathToPattern(__dirname)\n  const localMessageFiles = fg.sync(`${currentDir}/messages/**/*.ndjson`)\n  const tckMessageFiles = fg.sync(\n    `${currentDir}/../node_modules/@cucumber/compatibility-kit/features/**/*.ndjson`\n  )\n  const messageFiles = [].concat(localMessageFiles, tckMessageFiles)\n\n  it('must have some messages for comparison', () => {\n    assert.notEqual(messageFiles.length, 0)\n  })\n\n  for (const messageFile of messageFiles) {\n    it(`can walk through GherkinDocuments in ${messageFile}`, async () => {\n      const messageStream = new NdjsonToMessageStream()\n\n      await asyncPipeline(\n        fs.createReadStream(messageFile, 'utf-8'),\n        messageStream,\n        new Writable({\n          objectMode: true,\n          write(\n            envelope: messages.Envelope,\n            _encoding: string,\n            callback: (error?: Error | null) => void\n          ) {\n            try {\n              if (envelope.gherkinDocument) {\n                const walker = new GherkinDocumentWalker()\n                walker.walkGherkinDocument(envelope.gherkinDocument)\n              }\n              callback()\n            } catch (error) {\n              error.message += `\\n${envelope.gherkinDocument.uri}\\n`\n              callback(error)\n            }\n          },\n        })\n      )\n    }).timeout(30000)\n  }\n})\n"]}
